extends Node
## SetAutoPlay - 自动播放开关
## 切换自动转向模式，锁定/解锁玩家输入

@export var controller: AutoPlayController
@export var active: bool = false:
	set(value):
		active = value
		_apply_state()

var _player: Player

func _ready() -> void:
	if Engine.is_editor_hint():
		return
	await get_tree().process_frame
	_player = Player.instance
	_apply_state()

func toggle() -> void:
	active = !active

func _apply_state() -> void:
	if not controller:
		return
	controller.set_holder(active)
	if _player:
		_player.disallow_input = active

patch.new_text:
extends Node
## SetAutoPlay - 自动播放开关（与 Unity 版一致）
## 外部调用 toggle() 切换自动转向模式

@export var controller: AutoPlayController

var _active: bool = false

func toggle() -> void:
	_active = !_active
	if not controller:
		return
	controller.set_holder(_active)
	if controller.player:
		controller.player.disallow_input = _active
